import{_ as i,o as t,c as o,a0 as s}from"./chunks/framework.jwovEGr5.js";const u=JSON.parse('{"title":"Introduction to SwiftList","description":"","frontmatter":{},"headers":[],"relativePath":"guide/introduction.md","filePath":"guide/introduction.md"}'),n={name:"guide/introduction.md"};function a(r,e,l,d,c,g){return t(),o("div",null,[...e[0]||(e[0]=[s('<h1 id="introduction-to-swiftlist" tabindex="-1">Introduction to SwiftList <a class="header-anchor" href="#introduction-to-swiftlist" aria-label="Permalink to &quot;Introduction to SwiftList&quot;">​</a></h1><p>SwiftList is a high-performance, low-overhead, and highly extensible global search utility designed for Windows. It quickly builds and maintains indexes for local files, while offering a plugin SDK for developers to extend its capabilities.</p><h2 id="download-installation" tabindex="-1">Download &amp; Installation <a class="header-anchor" href="#download-installation" aria-label="Permalink to &quot;Download &amp; Installation&quot;">​</a></h2><p>SwiftList provides official installer and portable zip releases (Latest Stable Version):</p><ul><li>💾 <strong><a href="https://github.com/SwiftList/SwiftList/releases/latest/download/SwiftList-Setup.exe" target="_blank" rel="noreferrer">Download Installer</a></strong> — Full installer package (supports auto-start and background Windows Service indexing).</li><li>📦 <strong><a href="https://github.com/SwiftList/SwiftList/releases/latest/download/SwiftList-Portable.zip" target="_blank" rel="noreferrer">Download Portable Version</a></strong> — Standalone portable version.</li><li>🔍 Or visit <strong><a href="https://github.com/SwiftList/SwiftList/releases" target="_blank" rel="noreferrer">GitHub Releases Page</a></strong> to check all historical versions.</li></ul><h2 id="core-design-principles" tabindex="-1">Core Design Principles <a class="header-anchor" href="#core-design-principles" aria-label="Permalink to &quot;Core Design Principles&quot;">​</a></h2><ol><li><strong>YAGNI (You Aren&#39;t Gonna Need It)</strong>: Refuse bloated design; keep logic concise and execution fast.</li><li><strong>Process Separation &amp; Isolation</strong>: <ul><li><strong><code>SwiftList.Service</code> (System Service - <code>--service</code>)</strong>: Runs in Session 0 with SYSTEM privileges, indexing NTFS MFT and USN logs, shared globally.</li><li><strong><code>SwiftList.Service</code> (Hook Process - <code>--hook</code>)</strong>: Runs in the user session, capturing global keyboard hotkeys and tracking explorer paths.</li><li><strong><code>SwiftList.App</code> (User Application)</strong>: Runs in the user session, hosting UI interactions, rendering search results, and loading user-scoped plugins.</li></ul></li><li><strong>High-Speed FZF Matching</strong>: Optimized search matching supporting fuzzy queries, Pinyin initials, and customized aliases.</li></ol>',7)])])}const h=i(n,[["render",a]]);export{u as __pageData,h as default};
